class SamlAuthenticationToken extends AbstractAuthenticationToken {
    private final Object principal;
    private final String samlResponse;
    private final Map<String, List<String>> attributes;

    public SamlAuthenticationToken(String samlResponse) {
        super(Collections.emptyList());
        this.principal = null;
        this.samlResponse = samlResponse;
        this.attributes = new HashMap<>();
        setAuthenticated(false);
    }

    public SamlAuthenticationToken(Object principal, CollectionAuthorities authorities, Map<String, List<String>> attributes) {
        super(authorities.authorities);
        this.principal = principal;
        this.samlResponse = null;
        this.attributes = attributes == null ? new HashMap<>() : attributes;
        setAuthenticated(true);
    }

    @Override
    public Object getCredentials() {
        return samlResponse;
    }

    @Override
    public Object getPrincipal() {
        return principal;
    }

    public Map<String, List<String>> getAttributes() {
        return attributes;
    }

    static class CollectionAuthorities {
        private final List<GrantedAuthority> authorities;

        CollectionAuthorities(List<GrantedAuthority> authorities) {
            this.authorities = authorities;
        }
    }
}

@Component
class SamlAuthenticationFilter extends AbstractAuthenticationProcessingFilter {

    private final HttpSessionSecurityContextRepository securityContextRepository = new HttpSessionSecurityContextRepository();

    public SamlAuthenticationFilter(AuthenticationManager authenticationManager) {
        super(new AntPathRequestMatcher("/saml/acs", HttpMethod.POST.name()));
        setAuthenticationManager(authenticationManager);
        setAuthenticationSuccessHandler(successHandler());
        setAuthenticationFailureHandler(failureHandler());
    }

    @Override
    public Authentication attemptAuthentication(HttpServletRequest request, HttpServletResponse response) throws AuthenticationException, IOException, ServletException {
        String samlResponse = request.getParameter("SAMLResponse");
        if (!StringUtils.hasText(samlResponse)) {
            throw new SamlAuthenticationException("Missing SAMLResponse");
        }
        SamlAuthenticationToken authRequest = new SamlAuthenticationToken(samlResponse);
        return this.getAuthenticationManager().authenticate(authRequest);
    }

    private AuthenticationSuccessHandler successHandler() {
        return (request, response, authentication) -> {
            SecurityContext context = SecurityContextHolder.createEmptyContext();
            context.setAuthentication(authentication);
            SecurityContextHolder.setContext(context);
            securityContextRepository.saveContext(context, request, response);

            if (authentication instanceof SamlAuthenticatedPrincipal principal) {
                HttpSession session = request.getSession(true);
                session.setAttribute("SAML_NAME_ID", principal.getNameId());
                session.setAttribute("SAML_SESSION_INDEX", principal.getSessionIndex());
                session.setAttribute("SAML_ATTRIBUTES", principal.getAttributes());
            }

            response.setStatus(HttpServletResponse.SC_OK);
            response.setContentType("application/json");
            response.getWriter().write("{\"status\":\"authenticated\"}");
        };
    }

    private AuthenticationFailureHandler failureHandler() {
        return (request, response, exception) -> {
            response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
            response.setContentType("application/json");
            response.getWriter().write("{\"error\":\"" + exception.getMessage().replace("\"", "") + "\"}");
        };
    }
}

@Component
class SamlAuthenticationProvider implements org.springframework.security.authentication.AuthenticationProvider {

    private final SamlResponseProcessor samlResponseProcessor;

    public SamlAuthenticationProvider(SamlResponseProcessor samlResponseProcessor) {
        this.samlResponseProcessor = samlResponseProcessor;
    }

    @Override
    public Authentication authenticate(Authentication authentication) throws AuthenticationException {
        if (!(authentication instanceof SamlAuthenticationToken token)) {
            return null;
        }

        String encoded = (String) token.getCredentials();
        SamlPrincipalData principalData = samlResponseProcessor.process(encoded);

        List<GrantedAuthority> authorities = new ArrayList<>();
        authorities.add(new SimpleGrantedAuthority("ROLE_USER"));

        List<String> roles = principalData.attributes().getOrDefault("Role", Collections.emptyList());
        for (String role : roles) {
            if (StringUtils.hasText(role)) {
                String normalized = role.startsWith("ROLE_") ? role : "ROLE_" + role.toUpperCase().replace('-', '_').replace(' ', '_');
                authorities.add(new SimpleGrantedAuthority(normalized));
            }
        }

        SamlAuthenticatedPrincipal principal = new SamlAuthenticatedPrincipal(
            principalData.nameId(),
            principalData.sessionIndex(),
            principalData.attributes(),
            principalData.issuer(),
            principalData.subject()
        );

        return new SamlAuthenticationToken(principal, new SamlAuthenticationToken.CollectionAuthorities(authorities), principalData.attributes());
    }

    @Override
    public boolean supports(Class<?> authentication) {
        return SamlAuthenticationToken.class.isAssignableFrom(authentication);
    }
}

@Service
class SamlResponseProcessor {

    public SamlPrincipalData process(String base64Response) {
        try {
            byte[] decoded = Base64.getDecoder().decode(base64Response);
            Document document = parseXml(decoded);

            XPath xpath = createXPath();

            String statusCode = string(xpath, document, "/*[local-name()='Response']/*[local-name()='Status']/*[local-name()='StatusCode']/@Value");
            if (!statusCode.endsWith(":Success") && !"urn:oasis:names:tc:SAML:2.0:status:Success".equals(statusCode)) {
                throw new SamlAuthenticationException("SAML response status is not success");
            }

            String issuer = string(xpath, document, "/*[local-name()='Response']/*[local-name()='Issuer']/text()");
            String subject = string(xpath, document, "//*[local-name()='Assertion']/*[local-name()='Subject']/*[local-name()='NameID']/text()");
            String nameId = subject;
            String sessionIndex = string(xpath, document, "//*[local-name()='AuthnStatement']/@SessionIndex");
            String notBefore = string(xpath, document, "//*[local-name()='Conditions']/@NotBefore");
            String notOnOrAfter = string(xpath, document, "//*[local-name()='Conditions']/@NotOnOrAfter");

            validateTimeWindow(notBefore, notOnOrAfter);

            Map<String, List<String>> attributes = extractAttributes(xpath, document);

            if (!StringUtils.hasText(nameId)) {
                throw new SamlAuthenticationException("Missing NameID in assertion");
            }

            return new SamlPrincipalData(nameId, sessionIndex, attributes, issuer, subject);
        } catch (IllegalArgumentException e) {
            throw new SamlAuthenticationException("Invalid Base64 SAML response", e);
        } catch (SamlAuthenticationException e) {
            throw e;
        } catch (Exception e) {
            throw new SamlAuthenticationException("Failed to process SAML response", e);
        }
    }

    private Document parseXml(byte[] xmlBytes) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);

        DocumentBuilder builder = factory.newDocumentBuilder();
        return builder.parse(new ByteArrayInputStream(xmlBytes));
    }

    private XPath createXPath() {
        return XPathFactory.newInstance().newXPath();
    }

    private String string(XPath xpath, Document document, String expression) throws Exception {
        String result = (String) xpath.evaluate(expression, document, XPathConstants.STRING);
        return result == null ? "" : result.trim();
    }

    private Map<String, List<String>> extractAttributes(XPath xpath, Document document) throws Exception {
        NodeList attributeNodes = (NodeList) xpath.evaluate(
            "//*[local-name()='Assertion']/*[local-name()='AttributeStatement']/*[local-name()='Attribute']",
            document,
            XPathConstants.NODESET
        );

        Map<String, List<String>> attributes = new HashMap<>();
        for (int i = 0; i < attributeNodes.getLength(); i++) {
            Node attribute = attributeNodes.item(i);
            Node nameNode = attribute.getAttributes() != null ? attribute.getAttributes().getNamedItem("Name") : null;
            if (nameNode == null) {
                continue;
            }
            String name = nameNode.getNodeValue();
            NodeList children = attribute.getChildNodes();
            List<String> values = new ArrayList<>();
            for (int j = 0; j < children.getLength(); j++) {
                Node child = children.item(j);
                if ("AttributeValue".equals(child.getLocalName())) {
                    String value = child.getTextContent();
                    if (value != null) {
                        values.add(value.trim());
                    }
                }
            }
            attributes.put(name, values);
        }
        return attributes;
    }

    private void validateTimeWindow(String notBefore, String notOnOrAfter) {
        Instant now = Instant.now();

        if (StringUtils.hasText(notBefore)) {
            Instant nb = Instant.parse(notBefore);
            if (now.isBefore(nb)) {
                throw new SamlAuthenticationException("Assertion not yet valid");
            }
        }

        if (StringUtils.hasText(notOnOrAfter)) {
            Instant noa = Instant.parse(notOnOrAfter);
            if (!now.isBefore(noa)) {
                throw new SamlAuthenticationException("Assertion expired");
            }
        }
    }
}

