@Controller
class HomeController {

    @GetMapping("/")
    @ResponseBody
    public Map<String, Object> home(Authentication authentication, HttpSession session) {
        Map<String, Object> result = new HashMap<>();
        result.put("authenticated", authentication != null && authentication.isAuthenticated());
        result.put("principal", authentication != null ? authentication.getPrincipal() : null);
        result.put("nameId", session.getAttribute("SAML_NAME_ID"));
        result.put("sessionIndex", session.getAttribute("SAML_SESSION_INDEX"));
        result.put("attributes", session.getAttribute("SAML_ATTRIBUTES"));
        return result;
    }

    @PostMapping("/logout")
    @ResponseBody
    public Map<String, Object> logout(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }
        SecurityContextHolder.clearContext();
        return Collections.singletonMap("status", "logged_out");
    }
}